import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function getZkEvmIntelligence(walletAddress) {
  const [scroll, linea] = await Promise.all([
    client.BalanceService.getTokenBalancesForWalletAddress("scroll-mainnet", walletAddress),
    client.BalanceService.getTokenBalancesForWalletAddress("linea-mainnet", walletAddress),
  ]);
  return { scroll: scroll.data?.items, linea: linea.data?.items };
}
